import React, { useState, useEffect } from "react";
import './GestionCitas.css'
const estados = ["Todas", "Pendiente", "Confirmada", "Completada", "Cancelada"];

const medicoPrueba = {

}

function GestionCitas({ medico, citas, onBuscar }) {
    // Estados locales para filtros
    const [filterE, setFilterE] = useState("Todas");
    const [filterP, setFilterP] = useState("");

    // Manejo de búsqueda
    const handleSubmit = (e) => {
        e.preventDefault();
        if (onBuscar) onBuscar({ estado: filterE, paciente: filterP });
    };

    // Función para obtener la clase de estado
    const getEstadoClass = (estado) => {
        switch (estado) {
            case "Pendiente":
                return "status pending";
            case "Confirmada":
                return "status attended";
            case "Completada":
                return "status confirmed";
            case "Cancelada":
                return "status canceled";
            default:
                return "";
        }
    };

    return (
        <div className="main-content">
            <h2 className="page-title">
                Doctor - <span className="patient-name">{medico?.nombre}</span> - appointments
            </h2>
            {medico?.estadoAprob === "Pendiente" && (
                <div className="warning">Medico no aprobado aún</div>
            )}

            <form className="search-form" onSubmit={handleSubmit}>
                <div className="search-group">
                    <label htmlFor="status" className="search-label">Estado</label>
                    <select
                        id="status"
                        name="estado"
                        className="search-select"
                        value={filterE}
                        onChange={e => setFilterE(e.target.value)}
                    >
                        {estados.map(e => (
                            <option key={e} value={e}>{e}</option>
                        ))}
                    </select>
                </div>
                <div className="search-group">
                    <label htmlFor="doctor" className="search-label">Paciente</label>
                    <input
                        type="text"
                        id="doctor"
                        name="paciente"
                        className="search-input"
                        value={filterP}
                        onChange={e => setFilterP(e.target.value)}
                    />
                </div>
                <button type="submit" className="search-button">Search</button>
            </form>

            <div className="appointments">
                {citas?.map((cita) => (
                    <div key={cita.id} className="appointment">
                        <div className="row">
                            <img src="/images/camara.png" alt="Patient" className="patient-photo" />
                            <div className="appointment-details">
                                <h3>
                                    <strong>{cita.idPaciente?.nombre}</strong>
                                </h3>
                            </div>
                            <div className="appointment-details">
                                <span className="date">{cita.fecha}</span>
                                <span className="date">{cita.hora}</span>
                            </div>
                            <div className="appointment-details">
                                <span className={getEstadoClass(cita.estado)}>{cita.estado}</span>
                            </div>
                        </div>
                        <div className="appointment-actions row width30">
                            {cita.estado === "Pendiente" && (
                                <>
                                    <a href={`/presentation/citas/confirmar/${medico.id}/${cita.id}`}>
                                        <button className="attend-button">✔ Attend</button>
                                    </a>
                                    <a href={`/presentation/citas/cancelar/${medico.id}/${cita.id}`}>
                                        <button className="cancel-button">✖ Cancel</button>
                                    </a>
                                </>
                            )}
                            {cita.estado === "Confirmada" && (
                                <a href={`/presentation/citas/completar/${medico.id}/${cita.id}`}>
                                    <button className="attend-button">Completar</button>
                                </a>
                            )}
                            {cita.estado === "Completada" && (
                                <a href={`/presentation/citas/anotar/${cita.id}`}>
                                    <button className="view-button">🔍 View</button>
                                </a>
                            )}
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
}

export default GestionCitas;
